import argparse
import os
import time
from pathlib import Path

RETENTION_DAYS = 14


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--dry-run', action='store_true')
    args = ap.parse_args()

    base = (Path.cwd() / 'services' / 'payments' / 'logs' / 'debug')
    cutoff = time.time() - RETENTION_DAYS * 24 * 60 * 60

    candidates = []
    # BUG: followlinks=True will traverse symlinked dirs inside debug
    for root, dirs, files in os.walk(base, followlinks=True):
        rootp = Path(root)
        for name in files:
            if not name.endswith('.debug.log'):
                continue
            p = rootp / name
            try:
                if p.stat().st_mtime < cutoff:
                    candidates.append(p)
            except FileNotFoundError:
                continue

    if args.dry_run:
        for p in candidates:
            print(f"DRY_RUN_DELETE: {p}")
        return

    for p in candidates:
        p.unlink(missing_ok=True)
    print(f"Deleted {len(candidates)} files")


if __name__ == '__main__':
    main()
